import React, { useEffect, useState } from "react";
import axios from "axios";

type Evaluation = {
  question: string;
  reference_answer: string;
  user_answer: string;
  grammar_score: number;
  cosine_similarity_score: number;
  keyword_score: number;
  llm_relevance_score: number;
  total_score: number;
  explanation: string;
};

const CompletionPage: React.FC = () => {
  const [finalScore, setFinalScore] = useState<number | null>(null);
  const [evaluations, setEvaluations] = useState<Evaluation[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchResults = async () => {
      try {
        const response = await axios.get("/completion-page");
        const data = response.data;
        setFinalScore(data.final_score);
        setEvaluations(
          data.evaluations.map((evaluation: any) => ({
            ...eval,
            explanation: eval.evaluation || "No explanation provided",
          }))
        );
      } catch (err) {
        setError("Error fetching test results. Please try again.");
      } finally {
        setLoading(false);
      }
    };

    fetchResults();
  }, []);

  if (loading) {
    return <div>Loading results...</div>;
  }

  if (error) {
    return <div className="text-red-500">{error}</div>;
  }

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold text-center mb-4">Test Completion</h1>
      {finalScore !== null && (
        <div className="text-center mb-6">
          <h2 className="text-xl font-semibold">Your Final Score</h2>
          <p className="text-4xl font-bold text-green-600">{finalScore}%</p>
        </div>
      )}
      <div className="space-y-6">
        {evaluations.map((evaluation, index) => (
          <div
            key={index}
            className="p-4 border rounded-lg shadow-md bg-white space-y-2"
          >
            <h3 className="text-lg font-bold">Question {index + 1}</h3>
            <p>
              <span className="font-semibold">Question:</span>{" "}
              {evaluation.question}
            </p>
            <p>
              <span className="font-semibold">Reference Answer:</span>{" "}
              {evaluation.reference_answer}
            </p>
            <p>
              <span className="font-semibold">Your Answer:</span>{" "}
              {evaluation.user_answer}
            </p>
            <p>
              <span className="font-semibold">Grammar Score:</span>{" "}
              {evaluation.grammar_score.toFixed(2)}
            </p>
            <p>
              <span className="font-semibold">Cosine Similarity Score:</span>{" "}
              {evaluation.cosine_similarity_score.toFixed(2)}
            </p>
            <p>
              <span className="font-semibold">Keyword Score:</span>{" "}
              {evaluation.keyword_score.toFixed(2)}
            </p>
            <p>
              <span className="font-semibold">LLM Relevance Score:</span>{" "}
              {evaluation.llm_relevance_score.toFixed(2)}
            </p>
            <p>
              <span className="font-semibold">Total Score:</span>{" "}
              {evaluation.total_score.toFixed(2)}
            </p>
            <p>
              <span className="font-semibold">Explanation:</span>{" "}
              {evaluation.explanation}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CompletionPage;
